-- 4.3.2 Отдел мониторинга операций электронной коммерции
WITH ins AS (
  INSERT INTO t_p61016064_digital_innovation_i.dept_functions (project_id, dept_name, title, category, source_section_code)
  SELECT 1, 'Департамент финансового мониторинга (ДФМ)', v.title, v.category, '4.3.2'
  FROM (VALUES
    ('Обеспечение своевременного выявления и квалификации подозрительных операций клиентов – юридических и физических лиц, осуществляемых в форме перевода электронных денежных средств','control'),
    ('Осуществление мероприятий по анализу мерчантов и партнёров Банка в рамках процедуры регистрации оферты и (или) договора','analytical'),
    ('Разработка программ и процедур, направленных на выявление и предотвращение необычных операций (сделок), выявление совокупности подозрительных операций и (или) действий, в том числе при осуществлении Банком взаимодействия с лицами, участвующими в электронной коммерции, либо при предоставлении Банком услуг указанным лицам, в части, касающейся деятельности Отдела мониторинга операций электронной коммерции','methodology'),
    ('Осуществление выявления новых типов сомнительных финансовых схем, направленных на легализацию преступных доходов, или финансирование терроризма, в части, касающейся деятельности Отдела мониторинга операций электронной коммерции','analytical'),
    ('Осуществление подготовки аналитических заключений по результатам оценки (анализа) операций (сделок) клиентов для Руководителя с целью квалификации необычных операций (сделок) клиентов (обычные или подозрительные) Банка. Осуществление согласования платежей клиентов Банка с признаками сомнительности','analytical')
  ) AS v(title, category)
  RETURNING id, source_section_code
)
INSERT INTO t_p61016064_digital_innovation_i.function_org_units (function_id, org_unit_id, role, source_ref)
SELECT ins.id, u.id, 'owner', 'polozhenie'
FROM ins JOIN t_p61016064_digital_innovation_i.org_units u
  ON u.project_id = 1 AND u.code = '4.3.2' AND u.is_archived = false;

-- 4.4 Управление оценки деятельности клиентов
