  INSERT INTO t_p61016064_digital_innovation_i.dept_functions (project_id, dept_name, title, category, source_section_code)
  SELECT 1, 'Департамент финансового мониторинга (ДФМ)', v.title, v.category, '4.4'
  FROM (VALUES
    ('Взаимодействие с Банком России, Уполномоченным органом в рамках подготовки и предоставления сведений на их письменные запросы в рамках своей компетенции','communication'),
    ('Организация и контроль процесса по оценке потенциальных клиентов при приёме на обслуживание в Банк','control'),
    ('Осуществление профилактики подозрительной активности в деятельности клиентов во взаимодействии со структурными бизнес-подразделениями Банка','control'),
    ('Осуществление подготовки аналитических заключений по результатам оценки (анализа) операций (сделок) клиентов для Руководителя с целью их квалификации (обычные или подозрительные)','analytical'),
    ('Разработка программ и процедур, направленных на выявление и предотвращение подозрительной деятельности клиентов, на основании операций (сделок), совокупности подозрительных операций и (или) действий клиентов','methodology'),
    ('Консультирование работников профильных структурных подразделений Банка по вопросам, возникающим при реализации ПВК по ПОД/ФТ по функционалу Управления оценки деятельности клиентов','communication'),
    ('Разработка технических заданий для реализации Управлением систем комплаенс-контроля и управления рисками Департамента развития общебанковских систем по вопросам, входящим в компетенцию Управления оценки деятельности клиентов','methodology')
  ) AS v(title, category)
  RETURNING id, source_section_code
)
INSERT INTO t_p61016064_digital_innovation_i.function_org_units (function_id, org_unit_id, role, source_ref)
SELECT ins2.id, u.id, 'owner', 'polozhenie'
